     1→/**
     2→ * Database Error Handler Utility (F137)
     3→ * Provides consistent error handling and logging for all GraphQL resolver database operations
     4→ */
     5→
     6→/**
     7→ * Error types that can be identified from database error messages
     8→ */
     9→export type DatabaseErrorType =
    10→  | "unique_constraint"
    11→  | "foreign_key"
    12→  | "not_null"
    13→  | "check_constraint"
    14→  | "connection"
    15→  | "timeout"
    16→  | "unknown";
    17→
    18→/**
    19→ * Configuration for error handling
    20→ */
    21→export interface ErrorHandlerConfig {
    22→  /** The operation being performed (e.g., "fetching brand", "creating recommendation") */
    23→  operation: string;
    24→  /** The entity type being operated on (e.g., "Brand", "Mention") */
    25→  entityType?: string;
    26→  /** The entity ID if applicable */
    27→  entityId?: string;
    28→  /** Whether to log the error to console (default: true) */
    29→  logError?: boolean;
    30→}
    31→
    32→/**
    33→ * Result of a not-found check
    34→ */
    35→export interface NotFoundResult<T> {
    36→  found: true;
    37→  data: T;
    38→}
    39→
    40→/**
    41→ * Classifies a database error into a known type
    42→ * @param error - The error to classify
    43→ * @returns The classified error type
    44→ */
    45→export function classifyDatabaseError(error: unknown): DatabaseErrorType {
    46→  if (!(error instanceof Error)) return "unknown";
    47→
    48→  const message = error.message.toLowerCase();
    49→
    50→  if (message.includes("unique") || message.includes("duplicate")) {
    51→    return "unique_constraint";
    52→  }
    53→
    54→  if (message.includes("foreign key") || message.includes("violates foreign key")) {
    55→    return "foreign_key";
    56→  }
    57→
    58→  if (message.includes("not null") || message.includes("null value")) {
    59→    return "not_null";
    60→  }
    61→
    62→  if (message.includes("check constraint") || message.includes("violates check constraint")) {
    63→    return "check_constraint";
    64→  }
    65→
    66→  if (
    67→    message.includes("connection") ||
    68→    message.includes("connect") ||
    69→    message.includes("econnrefused")
    70→  ) {
    71→    return "connection";
    72→  }
    73→
    74→  if (message.includes("timeout") || message.includes("timed out")) {
    75→    return "timeout";
    76→  }
    77→
    78→  return "unknown";
    79→}
    80→
    81→/**
    82→ * Creates a user-friendly error message based on the error type and context
    83→ * @param errorType - The classified error type
    84→ * @param config - Error handler configuration
    85→ * @returns A user-friendly error message
    86→ */
    87→function createUserFriendlyMessage(
    88→  errorType: DatabaseErrorType,
    89→  config: ErrorHandlerConfig
    90→): string {
    91→  const entityName = config.entityType || "resource";
    92→
    93→  switch (errorType) {
    94→    case "unique_constraint":
    95→      return `A ${entityName.toLowerCase()} with this information already exists.`;
    96→
    97→    case "foreign_key":
    98→      return `Cannot complete ${config.operation}. Referenced ${entityName.toLowerCase()} does not exist or has associated records.`;
    99→
   100→    case "not_null":
   101→      return `Required field is missing for ${entityName.toLowerCase()}.`;
   102→
   103→    case "check_constraint":
   104→      return `Invalid data provided for ${entityName.toLowerCase()}.`;
   105→
   106→    case "connection":
   107→      return "Database connection failed. Please try again later.";
   108→
   109→    case "timeout":
   110→      return "Operation timed out. Please try again later.";
   111→
   112→    default:
   113→      return `Failed to complete ${config.operation}. Please try again later.`;
   114→  }
   115→}
