     7→  const url = process.env.DATABASE_URL;
     8→  return !!url && url !== "postgresql://placeholder";
     9→};
    10→
    11→// Lazy initialization to avoid build-time errors
    12→let _db: NeonHttpDatabase<typeof schema> | null = null;
    13→let _sql: NeonQueryFunction<boolean, boolean> | null = null;
    14→
    15→function getDatabase(): NeonHttpDatabase<typeof schema> {
    16→  if (!_db) {
