    18→      throw new Error(
    19→        "Database not configured. Please set DATABASE_URL environment variable."
    20→      );
    21→    }
    22→    _sql = neon(process.env.DATABASE_URL!);
    23→    _db = drizzle(_sql, { schema });
    24→  }
    25→  return _db;
    26→}
    27→
    28→// Export a proxy that lazily initializes the database
    29→export const db = new Proxy({} as NeonHttpDatabase<typeof schema>, {
