    14→      return pathname.startsWith(prefix);
    15→    }
    16→    return pathname === pattern;
    17→  });
    18→}
    19→
    20→// Public routes that don't require authentication
    21→const publicRoutes = [
    22→  "/",
    23→  "/sign-in(.*)",
    24→  "/sign-up(.*)",
    25→  "/onboarding(.*)",  // Allow onboarding wizard for testing
    26→  "/dashboard(.*)",  // Allow dashboard for testing
    27→  "/api/onboarding(.*)",  // Allow all onboarding APIs
    28→  "/api/webhooks(.*)",
    29→  "/api/health",
    30→  "/api/status",
    31→  "/_next(.*)",
    32→  "/static(.*)",
    33→  "/favicon.ico",
    34→  "/logo.svg",
    35→  "/robots.txt",
    36→  "/sitemap.xml",
    37→];
    38→
    39→// Development mode middleware (when Clerk is not configured)
    40→async function devMiddleware(request: NextRequest) {
    41→  const { pathname } = request.nextUrl;
    42→
    43→  // Check if this is a super-admin route
    44→  const isSuperAdminRoute = pathname.startsWith("/admin") || pathname.startsWith("/api/admin");
    45→
    46→  if (isSuperAdminRoute) {
    47→    // In dev mode, require DEV_SUPER_ADMIN=true for admin routes
    48→    const devSuperAdmin = process.env.DEV_SUPER_ADMIN === "true";
    49→
    50→    if (!devSuperAdmin) {
    51→      const url = new URL("/dashboard", request.url);
    52→      url.searchParams.set("error", "super_admin_required");
    53→      url.searchParams.set("message", "Set DEV_SUPER_ADMIN=true in .env to access admin panel");
    54→      return NextResponse.redirect(url);
    55→    }
    56→  }
    57→
    58→  // Allow all other routes in dev mode
    59→  return NextResponse.next();
    60→}
    61→
    62→// Production middleware with Clerk authentication
    63→async function productionMiddleware(request: NextRequest) {
    64→  // Dynamically import Clerk middleware only when configured
    65→  const { clerkMiddleware, createRouteMatcher } = await import(
    66→    "@clerk/nextjs/server"
    67→  );
    68→
    69→  const isPublicRoute = createRouteMatcher(publicRoutes);
    70→
    71→  const isOrgRoute = createRouteMatcher([
    72→    "/dashboard(.*)",
    73→    "/monitor(.*)",
    74→    "/create(.*)",
    75→    "/audit(.*)",
    76→    "/recommendations(.*)",
    77→    "/settings(.*)",
    78→    "/api/brands(.*)",
    79→    "/api/content(.*)",
    80→    "/api/audits(.*)",
    81→    "/api/recommendations(.*)",
    82→    "/api/monitoring(.*)",
    83→    "/api/portfolios(.*)",
    84→    "/api/reports(.*)",
    85→  ]);
    86→
    87→  // Super-admin routes (system-wide admin panel)
    88→  const isSuperAdminRoute = createRouteMatcher([
    89→    "/admin(.*)",
    90→    "/api/admin(.*)",
    91→  ]);
    92→
    93→  // Org-admin routes (organization-level settings)
    94→  const isOrgAdminRoute = createRouteMatcher([
    95→    "/settings/organization(.*)",
    96→    "/settings/billing(.*)",
    97→    "/settings/api-keys(.*)",
    98→  ]);
    99→
   100→  const handler = clerkMiddleware(async (auth, req) => {
   101→    // Allow public routes without authentication
   102→    if (isPublicRoute(req)) {
   103→      return;
   104→    }
   105→
   106→    // Protect all non-public routes
   107→    await auth.protect();
   108→
   109→    // For org routes, ensure user is part of an organization
   110→    if (isOrgRoute(req)) {
   111→      const { orgId } = await auth();
   112→      if (!orgId) {
   113→        return;
   114→      }
   115→    }
   116→
   117→    // For super-admin routes, check for super-admin status via publicMetadata
   118→    if (isSuperAdminRoute(req)) {
   119→      const { sessionClaims } = await auth();
   120→      const publicMetadata = sessionClaims?.publicMetadata as { isSuperAdmin?: boolean } | undefined;
   121→      const isSuperAdmin = publicMetadata?.isSuperAdmin === true;
   122→
   123→      // In development, allow access if DEV_SUPER_ADMIN is set
   124→      const devSuperAdmin = process.env.NODE_ENV === "development" && process.env.DEV_SUPER_ADMIN === "true";
   125→
   126→      if (!isSuperAdmin && !devSuperAdmin) {
   127→        const url = new URL("/dashboard", req.url);
   128→        url.searchParams.set("error", "super_admin_required");
   129→        return NextResponse.redirect(url);
   130→      }
   131→    }
   132→
   133→    // For org-admin routes, check for org:admin role
   134→    if (isOrgAdminRoute(req)) {
   135→      const { orgRole } = await auth();
   136→      if (orgRole !== "org:admin") {
   137→        const url = new URL("/dashboard", req.url);
   138→        url.searchParams.set("error", "unauthorized");
   139→        return NextResponse.redirect(url);
   140→      }
   141→    }
   142→  });
   143→
   144→  return handler(request, {} as never);
   145→}
   146→
   147→// Export middleware based on Clerk configuration
   148→export default async function middleware(request: NextRequest) {
   149→  if (!CLERK_CONFIGURED) {
   150→    return devMiddleware(request);
   151→  }
   152→  return productionMiddleware(request);
   153→}
   154→
   155→export const config = {
   156→  // Match all paths except static files
   157→  matcher: [
   158→    // Skip Next.js internals and all static files
   159→    "/((?!_next|[^?]*\\.(?:html?|css|js(?!on)|jpe?g|webp|png|gif|svg|ttf|woff2?|ico|csv|docx?|xlsx?|zip|webmanifest)).*)",
   160→    // Always run for API routes
   161→    "/(api|trpc)(.*)",
   162→  ],
   163→};
